#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        unsigned long long fact = 1ULL;
        while (n > 0) {
            fact *= (unsigned long long)n;
            n--;
        }
        printf("%llu\n", fact);
    }
    return 0;
}

