#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        n = int(data[idx]); idx += 1
        fact = 1
        while n > 0:
            fact *= n
            n -= 1
        out.append(str(fact))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

